#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char s[55];
    while(T--){
        scanf("%s",s);
        int groupsU=0, groupsD=0;
        int n=strlen(s);
        for(int i=0;i<n;){
            char cur=s[i];
            int j=i;
            while(j<n && s[j]==cur) j++;
            if(cur=='U') groupsU++; else groupsD++;
            i=j;
        }
        printf("%d\n", groupsU<groupsD?groupsU:groupsD);
    }
    return 0;
}

