code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T+1):
        s = data[i].strip()
        groupsU = groupsD = 0
        idx = 0
        n = len(s)
        while idx < n:
            cur = s[idx]
            j = idx
            while j < n and s[j] == cur:
                j += 1
            if cur == 'U':
                groupsU += 1
            else:
                groupsD += 1
            idx = j
        out.append(str(min(groupsU, groupsD)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

